operations.insert:
@font-face {
  font-family: "NeoDunggeunmo";
  src: url("dist/fonts/neodgm.ttf") format("truetype");
  font-weight: 400;
  font-style: normal;
  font-display: swap;
}

:root {
  --bb-kr-font-family: \"NeoDunggeunmo\", JetBrainsMono, \"Courier New\", monospace;
}
html body,
html body #root,
html body #root *:not(svg):not(path) {
  font-family: var(--bb-kr-font-family) !important;
}
input,
textarea,
button,
pre,
code,
.monaco-editor,
.monaco-editor * {
  font-family: var(--bb-kr-font-family) !important;
}
